from dataclasses import dataclass, field

@dataclass
class AgentScope:
    """Defines the complete capability scope for one agent session."""
    allowed_tools: set[str]
    denied_tools: set[str] = field(default_factory=set)
    max_tool_calls: int = 100
    max_cost_usd: float = 5.0
    max_wall_seconds: float = 1800.0
    read_only_paths: set[str] = field(default_factory=set)
    writable_paths: set[str] = field(default_factory=set)

# Scope for a read-only research agent
RESEARCH_AGENT_SCOPE = AgentScope(
    allowed_tools={"web_search", "read_file", "list_directory", "summarise"},
    denied_tools={"send_email", "deploy", "delete_file", "git_push", "execute_code"},
    max_tool_calls=50,
    max_cost_usd=1.0,
    max_wall_seconds=600.0,
    read_only_paths={"/workspace/docs", "/workspace/data"},
    writable_paths=set(),   # no writes
)

# Scope for a deployment agent
DEPLOY_AGENT_SCOPE = AgentScope(
    allowed_tools={"run_tests", "build", "push_image", "k8s_rollout"},
    denied_tools={"delete_database", "drop_table", "send_email"},
    max_tool_calls=20,
    max_cost_usd=10.0,
    max_wall_seconds=3600.0,
    writable_paths={"/artifacts", "/deploy-logs"},
)

class ScopedToolDispatcher:
    def __init__(self, scope: AgentScope, tool_registry: dict):
        self._scope = scope
        self._registry = tool_registry
        self._call_count = 0
        self._cost = 0.0

    def call(self, tool_name: str, arguments: dict, cost: float = 0.0) -> dict:
        if tool_name not in self._scope.allowed_tools:
            return {"error": f"Tool '{tool_name}' is outside the allowed scope for this session."}
        if tool_name in self._scope.denied_tools:
            return {"error": f"Tool '{tool_name}' is explicitly denied for this session."}
        if self._call_count >= self._scope.max_tool_calls:
            return {"error": f"Tool call limit ({self._scope.max_tool_calls}) reached."}
        if self._cost + cost > self._scope.max_cost_usd:
            return {"error": f"Cost cap (${self._scope.max_cost_usd}) would be exceeded."}

        self._call_count += 1
        self._cost += cost
        return self._registry[tool_name](**arguments)

import pathlib

class ScopedFileSystem:
    """
    File system abstraction that enforces path-level scope.
    The agent calls these methods instead of calling open() directly.
    """
    def __init__(self, allowed_read: list[str], allowed_write: list[str]):
        self._read_roots = [pathlib.Path(p).resolve() for p in allowed_read]
        self._write_roots = [pathlib.Path(p).resolve() for p in allowed_write]

    def _check_read(self, path: str) -> pathlib.Path:
        p = pathlib.Path(path).resolve()
        if not any(str(p).startswith(str(root)) for root in self._read_roots):
            raise PermissionError(
                f"Read access denied: '{p}' is outside the allowed read scope. "
                f"Allowed: {[str(r) for r in self._read_roots]}"
            )
        return p

    def _check_write(self, path: str) -> pathlib.Path:
        p = pathlib.Path(path).resolve()
        if not any(str(p).startswith(str(root)) for root in self._write_roots):
            raise PermissionError(
                f"Write access denied: '{p}' is outside the allowed write scope."
            )
        return p

    def read(self, path: str) -> str:
        p = self._check_read(path)
        return p.read_text(encoding="utf-8")

    def write(self, path: str, content: str) -> None:
        p = self._check_write(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_text(content, encoding="utf-8")

    def list_dir(self, path: str) -> list[str]:
        p = self._check_read(path)
        return [str(child) for child in p.iterdir()]

# Agent only sees /workspace/project — cannot path-traverse out
scoped_fs = ScopedFileSystem(
    allowed_read=["/workspace/project"],
    allowed_write=["/workspace/project/output"],
)

import time
from collections import defaultdict

class ActionRateLimiter:
    def __init__(self, limits: dict[str, tuple[int, float]]):
        # {tool_name: (max_calls, window_seconds)}
        self._limits = limits
        self._history: dict[str, list[float]] = defaultdict(list)

    def check_and_record(self, tool_name: str) -> tuple[bool, str]:
        """
        Returns (allowed, reason).
        Records the call if allowed.
        """
        if tool_name not in self._limits:
            return True, "no limit"

        max_calls, window = self._limits[tool_name]
        now = time.time()
        self._history[tool_name] = [
            t for t in self._history[tool_name] if now - t < window
        ]

        if len(self._history[tool_name]) >= max_calls:
            next_available = self._history[tool_name][0] + window
            return False, (
                f"Rate limit: {max_calls} calls per {window}s. "
                f"Next available in {next_available - now:.0f}s."
            )

        self._history[tool_name].append(now)
        return True, "ok"

CUSTOMER_SERVICE_LIMITS = ActionRateLimiter({
    "send_email":        (10, 3600),    # 10 emails/hour
    "create_ticket":     (20, 3600),    # 20 tickets/hour
    "lookup_account":    (100, 3600),   # 100 lookups/hour (read-heavy)
    "apply_discount":    (5, 86400),    # 5 discounts/day
})

import time, secrets, hashlib
from dataclasses import dataclass

@dataclass
class SessionCredential:
    session_id: str
    tool_token: str       # short-lived token for tool API calls
    expires_at: float     # Unix timestamp

    @classmethod
    def create(cls, duration_seconds: float = 1800.0) -> "SessionCredential":
        session_id = secrets.token_hex(16)
        # In production: issue a real short-lived token from your auth system
        tool_token = hashlib.sha256(
            (session_id + str(time.time())).encode()
        ).hexdigest()[:32]
        return cls(
            session_id=session_id,
            tool_token=tool_token,
            expires_at=time.time() + duration_seconds,
        )

    @property
    def is_valid(self) -> bool:
        return time.time() < self.expires_at

    @property
    def remaining_seconds(self) -> float:
        return max(0.0, self.expires_at - time.time())

class TimeScopedAgent:
    def __init__(self, scope: AgentScope):
        self._scope = scope
        self._credential = SessionCredential.create(scope.max_wall_seconds)
        self._start = time.time()

    def check_session_valid(self) -> None:
        if not self._credential.is_valid:
            raise RuntimeError(
                f"Session expired after {self._scope.max_wall_seconds}s. "
                "Create a new session to continue."
            )

    def elapsed(self) -> float:
        return time.time() - self._start
